1	// claim-office.ts
2	
3	type Customer = {
4	  yearsWithMHPCO: number;
5	};
6	
7	type Item = {
8	  type: string;
9	  material?: string;
10	  cursed?: boolean;
11	  enchantment?: number;
12	};
13	
14	type Damage = {
15	  itemType: string;
16	  amount: number;
17	};
18	
19	type Incident = {
20	  cause: string;
21	  damages: Damage[];
22	};
23	
24	type Step = {
25	  op: string;
26	  items?: Item[];
27	  policy?: number;
28	  incident?: Incident;
29	};
30	
31	type ScenarioInput = {
32	  customer: Customer;
33	  steps: Step[];
34	};
35	
36	type QuoteResult = {
37	  premium: number;
38	};
39	
40	type ClaimResult = {
41	  payout: number;
42	  remainingCap: number;
43	};
44	
45	type StepResult = QuoteResult | ClaimResult;
46	
47	type ScenarioOutput = {
48	  results: StepResult[];
49	};
50	
51	const PROCESSING_FEE = 5;
52	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
53	const CURSE_SURCHARGE_RATE = 0.5;
54	const HIGH_ENCHANTMENT_THRESHOLD = 5;
55	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
56	const LOYALTY_YEARS_THRESHOLD = 2;
57	const LOYALTY_DISCOUNT_RATE = 0.2;
58	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
59	const COMPONENT_BLOCK_SIZE = 3;
60	const COMPONENT_BLOCK_BASE_PREMIUM = 60;
61	const DEDUCTIBLE = 100;
62	const HIGH_REIMBURSEMENT_ENCHANTMENT_THRESHOLD = 8;
63	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
64	const FULL_REIMBURSEMENT_RATE = 1;
65	const CAP_MULTIPLIER = 2;
66	
67	const BASE_PREMIUMS: Record<string, number> = {
68	  sword: 100,
69	  amulet: 60,
70	  staff: 80,
71	  potion: 40,
72	  rune: 25,
73	  moonstone: 25,
74	};
75	
76	const INSURANCE_VALUES: Record<string, number> = {
77	  sword: 1000,
78	  amulet: 600,
79	  rune: 250,
80	};
81	
82	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
83	
84	const isComponentBlock = (type: string, count: number): boolean =>
85	  COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE;
86	
87	const basePremiumFor = (type: string): number => {
88	  const basePremium = BASE_PREMIUMS[type];
89	  if (basePremium === undefined) {
90	    throw new Error(`Unknown item type: ${type}`);
91	  }
92	  return basePremium;
93	};
94	
95	const surchargeFor = (
96	  items: Item[],
97	  applies: (item: Item) => boolean,
98	  rate: number
99	): number =>
100	  items.reduce(
101	    (surcharge, item) =>
102	      applies(item) ? surcharge + basePremiumFor(item.type) * rate : surcharge,
103	    0
104	  );
105	
106	const isCursed = (item: Item): boolean => item.cursed === true;
107	
108	const hasEnchantmentAtLeast = (
109	  item: Item | undefined,
110	  threshold: number
111	): boolean => (item?.enchantment ?? 0) >= threshold;
112	
113	const isHighlyEnchanted = (item: Item): boolean =>
114	  hasEnchantmentAtLeast(item, HIGH_ENCHANTMENT_THRESHOLD);
115	
116	const curseSurchargeFor = (items: Item[]): number =>
117	  surchargeFor(items, isCursed, CURSE_SURCHARGE_RATE);
118	
119	const enchantmentSurchargeFor = (items: Item[]): number =>
120	  surchargeFor(items, isHighlyEnchanted, HIGH_ENCHANTMENT_SURCHARGE_RATE);
121	
122	const groupBasePremium = (type: string, count: number): number =>
123	  isComponentBlock(type, count)
124	    ? COMPONENT_BLOCK_BASE_PREMIUM
125	    : count * basePremiumFor(type);
126	
127	const countByType = <T>(entries: T[], typeOf: (entry: T) => string) => {
128	  const counts = new Map<string, number>();
129	  for (const entry of entries) {
130	    const type = typeOf(entry);
131	    counts.set(type, (counts.get(type) ?? 0) + 1);
132	  }
133	  return counts;
134	};
135	
136	const policyBaseFor = (items: Item[]): number => {
137	  let policyBase = 0;
138	  for (const [type, count] of countByType(items, (item) => item.type)) {
139	    policyBase += groupBasePremium(type, count);
140	  }
141	  return policyBase;
142	};
143	
144	const qualifiesForLoyaltyDiscount = (customer: Customer): boolean =>
145	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
146	
147	const quotePremium = (
148	  items: Item[],
149	  customer: Customer,
150	  isFollowUp: boolean
151	): number => {
152	  const policyBase = policyBaseFor(items);
153	  const itemSurcharges =
154	    curseSurchargeFor(items) + enchantmentSurchargeFor(items);
155	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
156	  const loyaltyDiscount = qualifiesForLoyaltyDiscount(customer)
157	    ? policyBase * LOYALTY_DISCOUNT_RATE
158	    : 0;
159	  const followUpDiscount = isFollowUp
160	    ? policyBase * FOLLOW_UP_DISCOUNT_RATE
161	    : 0;
162	  return Math.ceil(
163	    policyBase +
164	      itemSurcharges +
165	      firstInsuranceSurcharge -
166	      loyaltyDiscount -
167	      followUpDiscount +
168	      PROCESSING_FEE
169	  );
170	};
171	
172	const isFollowUpQuote = (stepIndex: number): boolean => stepIndex > 0;
173	
174	const insuranceSumFor = (items: Item[]): number =>
175	  items.reduce((sum, item) => sum + INSURANCE_VALUES[item.type], 0);
176	
177	const reimbursementRateFor = (damagedItem: Item | undefined): number =>
178	  hasEnchantmentAtLeast(damagedItem, HIGH_REIMBURSEMENT_ENCHANTMENT_THRESHOLD)
179	    ? HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
180	    : FULL_REIMBURSEMENT_RATE;
181	
182	const insuredItemFor = (damage: Damage, policyItems: Item[]): Item => {
183	  const insuredItem = policyItems.find(
184	    (item) => item.type === damage.itemType
185	  );
186	  if (insuredItem === undefined) {
187	    throw new Error(`Damaged item not covered by policy: ${damage.itemType}`);
188	  }
189	  return insuredItem;
190	};
191	
192	const payoutForDamage = (damage: Damage, policyItems: Item[]): number =>
193	  damage.amount * reimbursementRateFor(insuredItemFor(damage, policyItems)) -
194	  DEDUCTIBLE;
195	
196	const initialCapFor = (policyItems: Item[]): number =>
197	  insuranceSumFor(policyItems) * CAP_MULTIPLIER;
198	
199	const assertDamagesCovered = (damages: Damage[], policyItems: Item[]): void => {
200	  const insuredCounts = countByType(policyItems, (item) => item.type);
201	  for (const [type, count] of countByType(
202	    damages,
203	    (damage) => damage.itemType
204	  )) {
205	    if (count > (insuredCounts.get(type) ?? 0)) {
206	      throw new Error(
207	        `More damages of type ${type} than insured items of that type`
208	      );
209	    }
210	  }
211	};
212	
213	const assertDamageAmountsNonNegative = (damages: Damage[]): void => {
214	  for (const damage of damages) {
215	    if (damage.amount < 0) {
216	      throw new Error(`Negative damage amount: ${damage.amount}`);
217	    }
218	  }
219	};
220	
221	const processClaim = (
222	  step: Step,
223	  steps: Step[],
224	  remainingCaps: Map<number, number>
225	): ClaimResult => {
226	  const policyIndex = step.policy!;
227	  const policyItems = steps[policyIndex].items ?? [];
228	  assertDamagesCovered(step.incident!.damages, policyItems);
229	  assertDamageAmountsNonNegative(step.incident!.damages);
230	  const remainingCap =
231	    remainingCaps.get(policyIndex) ?? initialCapFor(policyItems);
232	  const uncappedPayout = step.incident!.damages.reduce(
233	    (sum, damage) => sum + payoutForDamage(damage, policyItems),
234	    0
235	  );
236	  const payout = Math.floor(Math.min(uncappedPayout, remainingCap));
237	  const newRemainingCap = remainingCap - payout;
238	  remainingCaps.set(policyIndex, newRemainingCap);
239	  return { payout, remainingCap: newRemainingCap };
240	};
241	
242	const processQuote = (
243	  step: Step,
244	  customer: Customer,
245	  stepIndex: number
246	): QuoteResult => ({
247	  premium: quotePremium(step.items ?? [], customer, isFollowUpQuote(stepIndex)),
248	});
249	
250	export const processScenario = (input: ScenarioInput): ScenarioOutput => {
251	  const remainingCaps = new Map<number, number>();
252	  const results = input.steps.map((step, index) =>
253	    step.op === "claim"
254	      ? processClaim(step, input.steps, remainingCaps)
255	      : processQuote(step, input.customer, index)
256	  );
257	  return { results };
258	};
